const express = require('express');
const axios = require('axios');
const app = express();
const port = 3000;

app.use(express.json());

app.all('*', async (req, res) => {
    const apiKey = req.query.api_key;
    if (!apiKey) {
        return res.status(401).send('API key is required');
    }

    // Log the request including API key for debugging
    console.log(`Request to ${req.url} with API key: ${apiKey}`);

    try {
        const backendUrl = 'http://backend-service'; // Replace with actual backend URL
        const headers = { ...req.headers, 'X-API-Key': apiKey };
        delete headers['api_key']; // Remove the query parameter from headers

        const response = await axios({
            method: req.method,
            url: `${backendUrl}${req.url}`,
            headers,
            data: req.body
        });

        res.status(response.status).send(response.data);
    } catch (error) {
        console.error('Error forwarding request:', error);
        res.status(500).send('Internal Server Error');
    }
});

app.listen(port, () => {
    console.log(`API Gateway running on port ${port}`);
});